import redis.clients.jedis.Response;
import redis.clients.jedis.Transaction;

import java.util.List;
import java.util.Map;

/**
 * This class is extending Jedis Transaction
 */
public class RedisGraphTransaction extends Transaction
        implements com.redislabs.redisgraph.RedisGraphTransaction, RedisGraphCacheHolder {

    private final RedisGraph redisGraph;
    private RedisGraphCaches caches;
    private final CommandObjects commandObjects;

    public RedisGraphTransaction(Connection connection, RedisGraph redisGraph) {
        super(connection);
        this.redisGraph = redisGraph;
        this.commandObjects = new CommandObjects();
    }

    private enum RedisGraphCommand implements ProtocolCommand {
        QUERY, RO_QUERY, DELETE
    }

    /**
     * Execute a Cypher query.
     * @param graphId a graph to perform the query on
     * @param query Cypher query
     * @return a response which builds the result set with the query answer.
     */
    @Override
    public Response<ResultSet> query(String graphId, String query) {
        CommandObject<ResultSet> commandObject = new CommandObject<>(
            commandObjects.commandArguments(RedisGraphCommand.QUERY).add(graphId).add(query).add(Utils.COMPACT_STRING),
            new Builder<ResultSet>() {
                @SuppressWarnings("unchecked")
                @Override
                public ResultSet build(Object o) {
                    return new ResultSetImpl((List<Object>) o, redisGraph, caches.getGraphCache(graphId));
                }
            });
        return appendCommand(commandObject);
    }

    /**
     * Execute a Cypher read-oly query.
     * @param graphId a graph to perform the query on
     * @param query Cypher query
     * @return a response which builds the result set with the query answer.
     */
    @Override
    public Response<ResultSet> readOnlyQuery(String graphId, String query) {
        CommandObject<ResultSet> commandObject = new CommandObject<>(
            commandObjects.commandArguments(RedisGraphCommand.RO_QUERY).add(graphId).add(query).add(Utils.COMPACT_STRING),
            new Builder<ResultSet>() {
                @SuppressWarnings("unchecked")
                @Override
                public ResultSet build(Object o) {
                    return new ResultSetImpl((List<Object>) o, redisGraph, caches.getGraphCache(graphId));
                }
            });
        return appendCommand(commandObject);
    }

    /**
     * Execute a Cypher query with timeout.
     *
     * NOTE: timeout is simply sent to DB. Socket timeout will not be changed.
     * @param graphId a graph to perform the query on
     * @param query Cypher query
     * @param timeout
     * @return a response which builds the result set with the query answer.
     */
    @Override
    public Response<ResultSet> query(String graphId, String query, long timeout) {
        CommandObject<ResultSet> commandObject = new CommandObject<>(
            commandObjects.commandArguments(RedisGraphCommand.QUERY)
                .add(graphId).add(query).add(Utils.COMPACT_STRING).add(Utils.TIMEOUT_STRING).add(Long.toString(timeout)),
            new Builder<ResultSet>() {
                @SuppressWarnings("unchecked")
                @Override
                public ResultSet build(Object o) {
                    return new ResultSetImpl((List<Object>) o, redisGraph, caches.getGraphCache(graphId));
                }
            });
        return appendCommand(commandObject);
    }

    /**
     * Execute a Cypher read-only query with timeout.
     *
     * NOTE: timeout is simply sent to DB. Socket timeout will not be changed.
     * @param graphId a graph to perform the query on
     * @param query Cypher query
