     */
    public Response<String> deleteGraph(String graphId) {
        CommandObject<String> commandObject = new CommandObject<>(
            new CommandArguments(RedisGraphCommand.DELETE).add(graphId),
            redis.clients.jedis.BuilderFactory.STRING);
        Response<String> response = appendCommand(commandObject);
        caches.removeGraphCache(graphId);
        return response;
    }

    @Override
    public List<Response<?>> execGetResponse() {
        exec();
        return null;
    }

    @Override
    public void setRedisGraphCaches(RedisGraphCaches caches) {
        this.caches = caches;
    }

}

